var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"헉… 허억…….","JPN":"はぁ……はぁ……","ENG":"*Huff* *Huff*","TWN":"咳……咳咳……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"인간적으로 그만 좀 따라와요! 대체 뭐가 이렇게 끈질겨?","JPN":"これ以上ついてこないでください！　なんでこんなにしつこいの？","ENG":"Come on, just give up already! Why are you so persistent?!","TWN":"你們……你們能不能別再跟著我了！到底為什麼要一直纏著我！？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"그쪽이야말로 포기하라고, 형씨. 시간 끌면 서로 손해야.","JPN":"そっちこそ諦めろよ。長引けばお互いにいいことはない。","ENG":"You should be the one giving up. You're just wasting both of our time.","TWN":"該放棄的是你吧，小妹妹！拖下去對誰都沒好處。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"바보예요? 얌전히 잡힐 거였으면 도망치지도 않았겠죠!","JPN":"バカなんですか？　大人しく捕まるくらいなら逃げなかったでしょう！","ENG":"Are you stupid? I wouldn't run away if I were going to just give up!","TWN":"我是傻瓜嗎？如果打算乖乖被抓，就不會逃跑了吧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"크윽?! 내 귀가!","JPN":"くうっ！？　俺の耳が！","ENG":"Kgh?! My ears!","TWN":"呃？！我的耳朵！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"양쪽에서 포위해! 어차피 더는 도망칠 곳도 없어!","JPN":"両方から囲め！　どうせもう逃げられる場所はないんだ！","ENG":"Surround her! She has nowhere to run!","TWN":"兩邊包抄！反正她也無處可逃了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"치, 치사하게 여자 상대로 여럿이서 덤비기예요?","JPN":"お、女相手に数人でかかってくるなんて、ずるいじゃないですか！","ENG":"Th-that's unfair! You really want to outnumber one girl?","TWN":"哼，真卑鄙，居然一群人欺負一個女生？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"카운터면서 잘도 말하네. 그러게 왜 귀찮게 도망치고 난리야?","JPN":"カウンターのくせによく言うよ。なら、なぜ面倒に逃げ回るんだよ？","ENG":"You're a Counter, and it's only fair. See? Why did you have to run away in the first place?","TWN":"身為制裁者還說得這麼輕鬆。為什麼要這麼麻煩地逃跑呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"큽?!","JPN":"くぅっ！？","ENG":"Kgh?!","TWN":"咳？!"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_03"},{"id":"L30_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"휴우-. 이제 좀 조용하네. 이상한 짓 안 할 테니 얌전히 있으라고.","JPN":"ふうーやっと静かになったか。変なことはしないから、大人しくしてろよ。","ENG":"Phew. She's quiet now. Stay still, and we won't do anything bad.","TWN":"呼——，現在總算安靜了。別做奇怪的事，乖乖待著。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"너도 다치긴 싫잖아? 우리도 여자 상대로 쩔쩔매기는 싫거든.","JPN":"怪我はしたくないだろう？　俺たちも女相手に手を焼きたくないんだ。","ENG":"You don't want to get hurt, do you? We don't want to struggle against a girl, either.","TWN":"你也不想受傷吧？我們也不想對一個小女孩動粗。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"윽? 뭐하는 짓이야!","JPN":"うっ？　何してやがる！","ENG":"Kgh? What do you think you're doing?!","TWN":"呃？！你在幹什麼！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"베에-.","JPN":"ベーだ。","ENG":"Blegh!","TWN":"叭——"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"못 생겼으면서 폼잡기는. 그런 얼굴에 넘어갈 여자는 당신 어머니밖에 없다고요.","JPN":"ブサイクのくせにカッコつけて。そんな顔に惚れる女なんて、あなたのお母さんしかいないですよ。","ENG":"I'd keep that smolder to yourself. The only woman you're going to impress is your mother.","TWN":"長得醜還囂張什麼？會被你那張臉迷住的女人，恐怕只有你媽了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"툭 치면 날아갈 것처럼 약하면서 괜히 있어 보이는 표정이나 짓고.","JPN":"ちょっと叩いただけでもふっ飛びそうなくらい弱いくせに、強がった顔して。","ENG":"It's embarrassing to see you try so hard when we all know you're going to go flying with the slightest shove.","TWN":"明明弱不禁風，還在那邊裝模作樣！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"하. 때려달라고 에둘러서 표현하다니. 혹시 그런 쪽 취향인가?","JPN":"は。その言い方、殴られたいってか。もしかして、そっちの趣味があるのかよ？","ENG":"Hah. So you really do want to get beat up. Is that what floats your boat?","TWN":"哈！你想討打是吧？難道你有這種癖好？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마요. 진짜 날아갈 것 같으니까 조심하라고요.","JPN":"まさか。本当にふっ飛ぶと思いますから、気をつけてくださいって言ってるんですよ。","ENG":"Of course not. I think you're really going to be sent flying, so be careful.","TWN":"怎麼可能？我只是怕你真的飛走，所以提醒你小心點。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"싫으면 뭐라도 붙잡으시던가.","JPN":"それがイヤなら何か掴んどくことですね。","ENG":"Or hold on to something, at least.","TWN":"不喜歡的話，那就抓穩點吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"……응?","JPN":"……あ？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"자, 잠깐. 뭐야 저 거대한 오리는-!!","JPN":"ま、待てよ。なんだ、あの巨大なアヒルはー！！","ENG":"W-wait, what's that huge duck?!","TWN":"等、等等。那個巨大的鴨子……！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_EARTHQUAKE"},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오. 오래 기다렸다, 유피 선원! 시그마 선장님의 등장이야!","JPN":"おお。お待たせ、ユピ船員！　シグマ船長の登場だよ！","ENG":"Oh. Sorry to keep you waiting, Yuppie! Here's Captain Sigma!","TWN":"喔喔。久等了，悠菲船員！西格瑪船長登場了！"},"stage":{"bg":"DEBT_05","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"후후. 보물을 찾기 위해서라지만 설마 꼬마 해적들과 힘을 합치게 될 줄이야.","JPN":"ふふ。宝物を探すためだとは言え、まさかチビ海賊たちと力を合わせることになるとは。","ENG":"Ha ha. Even though it's to find treasure, I didn't expect I'd end up joining forces with little pirates.","TWN":"呵呵。雖然是為了尋找寶藏，但沒想到會和小海盜們聯手。"},"stage":{"bg":"DEBT_05","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"역시 세상 일은 모르고 볼 일이군.","JPN":"やはり、この世は予想不可能だ。","ENG":"I guess you truly never know what the future holds.","TWN":"果然世事難料啊。"},"stage":{"bg":"DEBT_05","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"……얼!","JPN":"……ARRR！","ENG":"...Yarr!","TWN":"……唷呵！"},"stage":{"bg":"DEBT_05","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님이랑… 뭐야, 브레멘 동물전대에 나오는 오리잖아?","JPN":"室長と……なんだ、ブレーメン動物戦隊に出るアヒルじゃない。","ENG":"Chief and... Wait, is that the duck from the Town Soldiers of Bremen?","TWN":"室長……什麼啊，這不是布萊梅動物戰隊裡的鴨子嗎？"},"stage":{"bg":"DEBT_05","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"크윽. 갑자기 이게 뭔 난리야?","JPN":"くうっ。いったいどうなってるんだ？","ENG":"Kgh, what's going on?","TWN":"呃，到底在搞什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"얕보는 것도 적당히 해야지…! 계집애 다음은 오리냐?","JPN":"舐めるのもいい加減にしろ……！　小娘の次はアヒルか？","ENG":"Enough with the underestimating...! First a girl, and now a duck?!","TWN":"別太小看人了……！先是個小女孩，然後是鴨子嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"우릴 무슨 엑스트라로 보는 거냐고!","JPN":"俺たちはエキストラじゃないんだよ！","ENG":"You think we're some kind of extras!?","TWN":"把我們當成什麼跑龍套的嗎！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"해적의 필수적인 3요소! 첫째는 보물에 대한 갈망, 둘째는 상황을 타개하는 순발력!","JPN":"海賊の3要素！　一つ、お宝への渇望。二つ、状況を打破する瞬発力！","ENG":"The three essential elements a pirate should have! The first is the yearning for treasure! The second is the quickness to overcome any situation!","TWN":"海盜的三大要素！首先是對寶藏的渴望，其次是是面對局勢的應變力！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"셋째는 바다로 나아가고자 하는 용기!","JPN":"三つ目は海に出ようとする勇気！","ENG":"The third is the courage to sail out to sea!","TWN":"第三是勇往直前的勇氣！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"그것들을 망각한 시점에서 결국 너희는 풋내기다.","JPN":"それらを忘却した時点で、結局お前らは青二才なんだよ。","ENG":"Once you forget them, you're nothing but lubbers.","TWN":"從你們忘記那些東西的那一刻起，你們終究只是菜鳥！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"풋내기 해적이 진정한 해적을 이길 수는 없는 법이지, 얼!","JPN":"青臭い海賊が真の海賊に勝てるわけはない、ARRR！","ENG":"Lubbers can't beat true pirates! Yarr!","TWN":"菜鳥海盜是贏不了真正的海盜的，唷呵！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"누가 해적이라는 거야!? 우린 용병이라고!","JPN":"誰が海賊だ！？　俺たちは傭兵だ！","ENG":"Who are you calling pirates?! We're mercenaries!","TWN":"誰說我們是海盜！？我們是傭兵！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"흥, 인정하지 않겠다면 답은 하나뿐이지.","JPN":"ふん、認めないなら答えは一つだ。","ENG":"Hmpf, if you choose to deny it, there's only one way to settle this.","TWN":"哼，不肯承認的話，那就只有一個辦法了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"음, 인정하지 않으면 답은 하나뿐이야!","JPN":"うん、認めないなら答えは一つだよ！","ENG":"Mm. If you choose to deny it, there's only one way!","TWN":"嗯，如果不承認的話，那就只有一個辦法了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_DUCK","text":{"KOREA":"해적 결투다!","JPN":"海賊決闘だ！","ENG":"A pirate duel!","TWN":"海盜決鬥！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"그러니까 사람 말을 좀…","JPN":"だから人の話を……","ENG":"Are you even listening–","TWN":"你們到底在沒在聽……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":" 으악-!!","JPN":" うわーっ！！","ENG":" Aaargh!","TWN":"呃啊啊——！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이럇~ 가라, 캡틴 바르바로사~.","JPN":"うりゃ～行け、キャプテンバルバロッサ～","ENG":"Giddyup! Go, Captain Barbarossa!","TWN":"嘿呀——，上吧，巴巴羅薩隊長——"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"흥. 이번만큼은 동맹이다.","JPN":"ふん、今回だけは同盟だ。","ENG":"Hmph. A temporary alliance.","TWN":"哼。這次就結盟吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"대해적의 힘을 빌려주도록 하지, 얼!","JPN":"大海賊の力を借りてやる、ARRR！","ENG":"I'll lend you the power of the great pirate! Yarr!","TWN":"暫時把大海盜的力量借給你吧，唷呵！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하하.","JPN":"はは。","ENG":"Ha ha.","TWN":"哈哈。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"진짜 뭐가 뭔지…….","JPN":"本当に何が何だか……","ENG":"I don't understand anything that's going on...","TWN":"到底什麼跟什麼……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유-피-!!","JPN":"ユーピー！！","ENG":"Yuuuppieee!","TWN":"悠—菲—！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아야야… 오랜만에 보니 반갑네요, 실장님.","JPN":"いたた……久しぶりに会うと嬉しいですね、室長。","ENG":"Ouch... Good to see you, Chief.","TWN":"哇……好久不見，室長。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그동안 별일 없었죠?","JPN":"無事でしたか？","ENG":"How have you been?","TWN":"這段時間沒什麼特別的事吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응. 유피도 무사해서 다행이다.","JPN":"うん。ユピも無事でよかったよ。","ENG":"Good. I'm glad you're okay.","TWN":"太好了。悠菲也沒事，真是太好了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"미안해? 더 빨리 오려고 했는데 바르바로사를 설득하는 게 늦어버렸어.","JPN":"ごめんね？　もっと早く来たかったんだけど、バルバロッサを説得するのに時間がかかっちゃった。","ENG":"Sorry. I wanted to come get you earlier, but it took a while to convince Barbarossa.","TWN":"抱歉，我本來想早點來的，但說服巴巴羅薩花了點時間。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"괜찮아요. 지금 이렇게 구해주셨는걸요.","JPN":"大丈夫ですよ。今こうやって助けてくれたじゃないですか。","ENG":"It's all good. You're here for me now.","TWN":"沒關係，現在你救了我。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응! 그리고 유피가 없을 때 보물이 있는 장소도 알아냈다?","JPN":"うん！　それに、ユピがいない間にお宝がある場所もわかったよ。","ENG":"Yeah! And I found out where the treasure was while you were away!","TWN":"嗯！而且在悠菲不在的時候，西格瑪還找到了寶藏的位置？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"크레데레가 유피를 구하러 간 사이에……","JPN":"クレデレがユピを助けに行ってた間……","ENG":"While Credere went to save you–","TWN":"在克蕾妲莉去救悠菲的時候……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어라, 그러고보니 크레데레는?","JPN":"あれ、そういえばクレデレは？","ENG":"Huh? Where's Credere?","TWN":"咦？對了，克蕾妲莉呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저도 모르겠네요. 분명 헤어질 때 항구에서 만나기로 했는데.","JPN":"私もわからないんです。別れた時に、港で会う約束をしたんですけど。","ENG":"I don't know. We said we'd meet at the port.","TWN":"我也不知道……明明說好在港口見面的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"거, 거기 서…….","JPN":"ま、待って……","ENG":"S-stop right there...","TWN":"站住……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"부탁이니까 제발 서주세요…….","JPN":"お願いですから、どうか待ってください……","ENG":"Please, please stop...","TWN":"拜託，別再跑了……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"얍.","JPN":"やあっ。","ENG":"Yap.","TWN":"嘿。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L8_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":" 얍.","JPN":" やあっ。","ENG":" Yap.","TWN":"嘿。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L10_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":" 얍.","JPN":" やあっ。","ENG":" Yap.","TWN":"嘿。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"크레데레!","JPN":"クレデレ！","ENG":"Credere!","TWN":"克蕾妲莉！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"반갑긴 한데 뭔가 늘어났잖아! 또 사고 친 거예요, 당신?","JPN":"また会えて嬉しいけど、なんか増えてる！　また何をしでかしたんですか、あなた？","ENG":"I'm glad to see you, but why do you have company?! Did you get into trouble again?","TWN":"雖然見到你很開心，但你後面怎麼又多了兩個拖油瓶！克蕾妲莉又闖禍了，是不是？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"억울합니다. 크레데레를 문제아 취급하지 마시죠.","JPN":"失礼な。クレデレを問題児扱いしないでください。","ENG":"Credere feels falsely accused. Credere is not a problem child.","TWN":"冤枉，克蕾妲莉可不是問題兒童。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"한 발로만 뛰어온 이유는?","JPN":"片足でジャンプしてきた理由は？","ENG":"And why did you jump here on one foot?","TWN":"還有為什麼只用一條腿跑過來？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"저깟 놈들. 한 발로도 충분.","JPN":"あんなやつら。片足でも十分。","ENG":"One foot is enough for those chumps.","TWN":"面對那些傢伙。用一條腿就夠了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아하. 입력 장치를 두 개 쓰면 리소스 낭비인 것과 같은 원리구나?","JPN":"なるほど。入力装置を二つ使うとリソースの無駄遣いになるのと同じ原理だね。","ENG":"Aha. It's the same as wasting resources when you use two input devices!","TWN":"哈哈，我懂，就像用兩個輸入裝置一樣是資源浪費，對吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이상한 비유로 이해하지 마세요! 뒤는 바다라 도망갈 데도 없다고요!","JPN":"変な例えで理解しないでください！　後ろは海だから、逃げ場もないんです！","ENG":"Don't try to interpret that with weird metaphors! And there's nothing but water behind us, so we have nowhere to run!","TWN":"別用奇怪的比喻來解釋！我們後面是大海，根本無處可逃！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"얼…! 나를 잊으면 섭하지, 풋내기들.","JPN":"ARRR……！　俺のことを忘れると困るぞ、青二才ども。","ENG":"Yarr...! Don't forget about me, lubbers.","TWN":"唷呵——！要是忘了我會傷心的，菜鳥們！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"해적의 길은 육지가 아닌 바다에 있는 법이다.","JPN":"海賊の道は陸ではなく、海にあるものだ。","ENG":"A pirate ventures forth on water, not land.","TWN":"海盜的道路不在陸地，而在海上。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어라. 바르바로사 씨는 물을 무서워하는 게 아니었나요?","JPN":"あれ。バルバロッサさんって水が怖いんじゃなかったんですか？","ENG":"Wait. I thought you were afraid of water, Barbarossa.","TWN":"咦，巴巴羅薩隊長不是怕水嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"애들이 보던 설정집에 그렇게 적혀 있던 것 같은데.","JPN":"子どもたちが見ていた設定集にはそう書かれてたような。","ENG":"I think that's what it said in the backstory book that the kids were reading.","TWN":"……我記得人物設定是這樣寫的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"흥. 그런 편협한 생각으론 보물을 차지할 수 없지.","JPN":"ふん。そんな偏狭な考え方では宝物を手に入れることはできない。","ENG":"Hmph. Such narrow-minded thinking will not guide you to treasure.","TWN":"哼。用那種狹隘的想法是無法得到寶物的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DUCK_EXTRA_NULL_NULL","text":{"KOREA":"특별히 등을 빌려주마, 풋내기들! 보물이 있는 곳까지 순식간에 가는 거다!","JPN":"特別に背中を貸してやる、青二才ども！　宝物のあるところまで一瞬で行くのだ！","ENG":"I'll lend you my back, lubbers! We'll sail to the treasure in an instant!","TWN":"特別把我的背借給你們吧，菜鳥們！我們即刻便要抵達寶藏所在之地！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"와우.","JPN":"ワオ。","ENG":"Wow.","TWN":"喔——！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"왜 그러지, 풋내기… 응?","JPN":"どうした、青二才……うん？","ENG":"What is it, lubber– Hmm?","TWN":"怎麼了，菜鳥……嗯？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"아니?! 어째서 나의 탱글탱글한 몸이 이렇게 변한 거지?","JPN":"うお？　なぜ俺のぷりっぷりの体がこうなったんだ？","ENG":"What?! My body is losing its shape!","TWN":"不？！怎麼回事，我那圓滾滾豐滿的身體怎麼會變成這樣！？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"캡틴 바르바로사아-!!","JPN":"キャプテン・バルバロッサァー！！","ENG":"Captain Barbarossaaaa!","TWN":"巴巴羅薩隊長——!!"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"미쳤어요, 크레데레? 아무리 그래도 공기 마개를 열어버리면 어떡해요?","JPN":"何してるんですか、クレデレ！　いくらなんでも空気注入口のキャップを開けちゃったらダメでしょう！","ENG":"Are you insane, Credere? You can't just open the air valve!","TWN":"你是瘋了嗎，克蕾妲莉？再怎麼說也不能隨便打開空氣閥啊？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레가 아닙니다. 강한 바람이 오리 씨의 몸에 구멍을 낸 거예요.","JPN":"クレデレではありません。強い風がアヒルさんの体に穴を開けたんです。","ENG":"It was not Credere's doing. The strong wind made a hole in Mr. Duck's body.","TWN":"不是克蕾妲莉做的，是強風在鴨鴨身上吹出一個洞。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…네? 바람은 바르바로사 씨의 몸에서 나온 게 아니었어요?","JPN":"……え？　風って、バルバロッサさんの体から出たわけじゃないんですか？","ENG":"...What? The wind wasn't coming from Barbarossa's body?","TWN":"……什麼意思？風不是從巴巴羅薩先生的身體裡出來的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마 크레데레를 쫓던 분들이-","JPN":"まさか、クレデレを追っていた人たちがー","ENG":"Then, was it the people who were chasing you–","TWN":"難道是追著克蕾妲莉的那些人……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"없잖아? 그분들도 바람에 날아간 걸까요?","JPN":"いない？　あの方たちも風に飛ばされたんでしょうか？","ENG":"They're gone. Did they get swept up in the wind?","TWN":"人呢？她們也被風吹走了嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIBBON_DEBT_NPC_NULL","text":{"KOREA":"그 둘이라면 할 일이 생겼다며 황급히 돌아가더군.","JPN":"あの二人なら用事があると急いで帰っていたぞ。","ENG":"Those two returned in a hurry, saying that something came up.","TWN":"她們說還有事要做，匆忙回去了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"갈등을 빚지 않아 다행이네. 부사장의 명령은 어디까지나 섬멸이 아닌 포획이었으니.","JPN":"トラブルが起こらなくてよかったな。副社長の命令は、あくまでも殲滅ではなく捕獲だったはず。","ENG":"I am glad that no conflict was born, as the Vice President's order was to capture, not eliminate.","TWN":"很高興沒引起衝突，副總的命令畢竟是活捉。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_AIR_SMALL_START_04"},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"할아버지!","JPN":"おじいちゃん！","ENG":"Grandpa!","TWN":"爺爺！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"할아버지? 바르바로사 씨처럼 실장님이 부른 건가요?","JPN":"おじいちゃん？　バルバロッサさんと同様、室長が呼んだんですか？","ENG":"Grandpa? Did you call him, Chief? Like you did Barbarossa?","TWN":"爺爺？巴巴羅薩隊長和這位爺爺都是室長找來嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그것보다 포획이라니… 그게 무슨.","JPN":"それより捕獲って……いったいどういう？","ENG":"Wait, but \\"capture\\"...? What's that about?","TWN":"比起這個，活捉……是什麼意思？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"할아버지? 뭐하는 거야?","JPN":"おじいちゃん？　何してるの？","ENG":"Grandpa? What are you doing?","TWN":"爺爺？你在做什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"미안하네, 시그마.","JPN":"すまないな、シグマ。","ENG":"I'm sorry, Sigma.","TWN":"抱歉，西格瑪。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이 타이탄은 시그마가 잘못된 길에 빠지려는 것을 간과할 수 없다네.","JPN":"このタイタン、シグマが誤った道に進もうとしているところを見過すことはできないのだ。","ENG":"I cannot stand by and watch you go down the wrong path.","TWN":"身為泰坦不能忽視西格瑪走上歧途的可能性。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"수감번호 G1-24601. 무기를 버리고 즉시 투항하도록!","JPN":"収容番号G1-24601。武器を捨てて直ちに投降しろ！","ENG":"Prisoner G1-24601. Drop your weapons and surrender at once!","TWN":"囚犯編號G1-24601。放下武器，立刻投降！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_AIR_SMALL_START_04"},{"id":"L20_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그렇지 않으면…….","JPN":"さもなければ……","ENG":"Or else...","TWN":"不然的話……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"나의 빛나는 아틀라틀 포신에 맹세코, 자네의 안전은 보장할 수 없다네!","JPN":"吾輩の輝くアトラトル砲身に誓って、君の安全は保証できない！","ENG":"I swear on my brilliant Atlatl barrel, I cannot guarantee your well-being!","TWN":"我以耀眼的阿特拉托機槍起誓，無法保證你的安全！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};